// Supporte $json.body.xxx (webhook v2.1) et $json.xxx (fallback)
const raw = $input.first().json;
const d = raw.body || raw;

const nom = d.nom || 'Contact site';
const today = new Date().toISOString().split('T')[0];

const properties = {
  Nom: { title: [{ text: { content: nom } }] },
  Email: { email: d.email || null },
  Statut: { select: { name: '\u{1F195} Nouveau' } },
  Source: { select: { name: '\u{1F4DD} Formulaire contact' } },
};

if (d.telephone) {
  properties['\u00E9l\u00E9phone'] = { phone_number: d.telephone };
}
if (d.etablissement) {
  properties['Restaurant'] = { rich_text: [{ text: { content: d.etablissement } }] };
}
if (d.ville) {
  properties['Ville'] = { rich_text: [{ text: { content: d.ville } }] };
}

const noteLines = [
  d.message || null,
  d.note_google ? 'Note Google : ' + d.note_google : null,
  d.volume_avis ? 'Volume avis : ' + d.volume_avis : null,
  d.profil_quiz ? 'Profil quiz : ' + d.profil_quiz + (d.score_quiz ? ' (score ' + d.score_quiz + '/18)' : '') : null,
].filter(Boolean);

if (noteLines.length) {
  properties['Notes'] = { rich_text: [{ text: { content: noteLines.join('\n') } }] };
}

return [{
  json: {
    parent: { database_id: 'bea71342-e846-41ef-b477-fe218aa6793c' },
    properties
  }
}];
